## ============================================================================
## External Library Generator
## Generates external_libs_generated.nim based on installed libraries
## Run with: nim c -r src/harding/external/generator.nim
## ============================================================================

import std/[os, strutils, strformat]
import discovery

const
  OutputFile = "src/harding/external/external_libs_generated.nim"

proc generateHeader(): string =
  ## Generate file header
  result = """## ============================================================================
## External Libraries Integration
## AUTO-GENERATED by nimble discover - DO NOT EDIT
## ============================================================================

import std/strutils
import ../core/types
import discovery
"""

proc generateImports(libs: seq[LibraryInfo]): string =
  ## Generate import statements for each library
  result = "\n## Conditional imports for each installed library\n"

  if libs.len == 0:
    result.add("## (No libraries currently installed)\n")
    return result

  for lib in libs:
    let flag = getLibraryCompileFlag(lib.name).replace("-d:", "")
    let hardingModule = getExternalDir() / lib.name / "src" / lib.name / ("harding" & lib.name & ".nim")
    let mainModule = if fileExists(hardingModule):
                       "harding" & lib.name
                     else:
                       lib.name
    let importPath = lib.name & "/src/" & lib.name & "/" & mainModule

    result.add(&"\nwhen defined({flag}):\n")
    result.add(&"  import {importPath}\n")

  return result

proc generateInstaller(libs: seq[LibraryInfo]): string =
  ## Generate the installExternalLibraries proc
  result = """

## ============================================================================
## Library Installation
## ============================================================================

proc installExternalLibraries*(interp: var Interpreter) =
  ## Install all discovered and enabled external libraries.
  ##
  ## This proc is called by loadStdlib after the standard library is loaded.
  ## Each library is conditionally compiled based on whether it's installed
  ## and enabled via compile flags.

  let installedLibs = discoverInstalledLibraries()
  discard installedLibs

"""

  if libs.len == 0:
    result.add("  ## No external libraries installed\n")
    result.add("  debug(\"No external libraries found in external/\")\n")
    return result

  result.add("  debug(\"Installing external libraries...\")\n\n")

  for lib in libs:
    let installProc = "install" & getLibraryHardingName(lib.name)
    let flag = getLibraryCompileFlag(lib.name).replace("-d:", "")

    result.add(&"  ## {lib.name} ({lib.version})\n")
    result.add(&"  when defined({flag}):\n")
    result.add(&"    try:\n")
    result.add(&"      {installProc}(interp)\n")
    result.add(&"      debug(\"External library installed: {lib.name}\")\n")
    result.add(&"    except:\n")
    result.add(&"      warn(\"Failed to install library: {lib.name}\")\n")
    result.add(&"  else:\n")
    result.add(&"    debug(\"Library {lib.name} not enabled at compile time\")\n")
    result.add("\n")

  result.add("  debug(\"External library installation complete\")\n")

  return result

proc generateCompileFlagsProc(libs: seq[LibraryInfo]): string =
  ## Generate a proc that returns compile flags for installed libraries
  result = """

## ============================================================================
## Compile Flags Generation
## ============================================================================

proc getExternalCompileFlags*(): string =
  ## Get compile flags for all installed external libraries.
  ##
  ## This is used by the build system to automatically enable
  ## all installed libraries when compiling Harding.
  var flags: seq[string] = @[]

"""

  if libs.len == 0:
    result.add("  ## No libraries installed\n")
  else:
    for lib in libs:
      let flag = getLibraryCompileFlag(lib.name)
      result.add(&"  flags.add(\"{flag}\")\n")

  result.add("\n  return flags.join(\" \")\n")

  return result

proc generateBuiltLibrariesProc(libs: seq[LibraryInfo]): string =
  ## Generate a proc that reports which libraries were compiled into this binary
  result = """

## ============================================================================
## Built Libraries
## ============================================================================

proc getBuiltExternalLibraries*(): seq[string] =
  ## Get the external libraries compiled into the current binary.

"""

  if libs.len == 0:
    result.add("  discard\n")
    result.add("  return @[]\n")
    return result

  for lib in libs:
    let flag = getLibraryCompileFlag(lib.name).replace("-d:", "")
    let label = if lib.version.len > 0: lib.name & " (" & lib.version & ")" else: lib.name
    result.add(&"  when defined({flag}):\n")
    result.add(&"    result.add(\"{label}\")\n")

  result.add("\n  return result\n")

proc generateExternalLibsFile*() =
  ## Generate the external_libs_generated.nim file
  echo "Discovering installed libraries..."

  let libs = discoverInstalledLibraries()

  echo &"Found {libs.len} installed library(s):"
  for lib in libs:
    echo &"  - {lib.name} v{lib.version}"

  var content = generateHeader()
  content.add(generateImports(libs))
  content.add(generateInstaller(libs))
  content.add(generateCompileFlagsProc(libs))
  content.add(generateBuiltLibrariesProc(libs))

  echo &"\nGenerating {OutputFile}..."
  writeFile(OutputFile, content)
  echo "Done!"

  if libs.len > 0:
    echo "\nCompile flags for next build:"
    echo generateCompileFlags(libs)

when isMainModule:
  generateExternalLibsFile()
